import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { contentApi } from '../services/api';
import ContentGrid from '../components/ContentGrid';
import './Home.css';

export default function Home() {
  const [featured, setFeatured] = useState([]);
  const [trending, setTrending] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([
      contentApi.getAll({ featured: 'true' }),
      contentApi.getAll({ trending: 'true' }),
    ])
      .then(([f, t]) => {
        setFeatured(f);
        setTrending(t);
      })
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  if (loading) return <div className="page-loading">Loading...</div>;

  return (
    <div className="home">
      <section className="hero">
        <div className="hero-content">
          <p className="hero-tag">@verydirect on Instagram</p>
          <h1>Very Direct</h1>
          <p className="hero-sub">
            Raw stories, bold videos, and honest blogs — no filter, just real content.
          </p>
          <div className="hero-cta">
            <Link to="/videos" className="btn btn-primary">
              Watch Videos
            </Link>
            <Link to="/blogs" className="btn btn-outline">
              Read Blogs
            </Link>
          </div>
        </div>
      </section>

      <section className="section">
        <div className="section-header">
          <h2>Featured</h2>
          <span className="section-line" />
        </div>
        <ContentGrid items={featured} emptyMessage="No featured content yet." />
      </section>

      <section className="section">
        <div className="section-header">
          <h2>Trending</h2>
          <span className="section-line" />
        </div>
        <ContentGrid items={trending} emptyMessage="No trending content yet." />
      </section>
    </div>
  );
}
